option-b.script-outline:
var s1 = ee.ImageCollection('COPERNICUS/S1_GRD')
  .filterBounds(nepal_geometry)
  .filterDate('2024-06-01', '2024-09-30')
  .filter(ee.Filter.eq('instrumentMode', 'IW'))
  .select('VV');
var before = s1.filterDate('2024-06-01','2024-06-13').mean();
var after  = s1.filterDate('2024-06-14','2024-06-26').mean();
var change = after.subtract(before);
